  1→import { useCallback, useEffect, useState } from 'react';
  2→import './profilepostcards.css';
  3→import '../../Editor/editor.css';
  4→import { AnimatePresence, motion} from 'framer-motion';
  5→import { LexicalComposer } from '@lexical/react/LexicalComposer';
  6→import { HeadingNode, QuoteNode } from '@lexical/rich-text';
  7→import ImageNode from '../../Editor/nodes/ImageNode';
  8→import { RichTextPlugin } from '@lexical/react/LexicalRichTextPlugin';
  9→import LexicalErrorBoundary from '@lexical/react/LexicalErrorBoundary';
 10→import { ContentEditable } from '@lexical/react/LexicalContentEditable';
 11→import ToolBar from '../../Editor/Toolbar';
 12→import ImagePlugin from '../../Editor/nodes/Plugins/ImagePlugin';
 13→import { OnChangePlugin } from '@lexical/react/LexicalOnChangePlugin';
 14→import { HistoryPlugin } from '@lexical/react/LexicalHistoryPlugin';
 15→import { updateJournal } from '../../../../../API/Api';
 16→import { useAuth } from '../../../../Context/useAuth';
 17→import { BarLoader } from 'react-spinners';
 18→import { useQueryClient } from '@tanstack/react-query';
 19→
 20→const EditJournal = ({onClose, journalData}) => {
 21→    const {session, user} = useAuth();
 22→    const queryClient = useQueryClient();
 23→
 24→    const theme = {
 25→        paragraph: 'editor-paragraph',
 26→        heading: {
 27→            h1: 'editor-heading-h1',
 28→            h2: 'editor-heading-h2',
 29→            h3: 'editor-heading-h3',
 30→        },
 31→        quote: 'editor-quote',
 32→        text: {
 33→            bold: 'editor-text-bold',
 34→            italic: 'editor-text-italic',
 35→            underline: 'editor-text-underline',
 36→        }
 37→    }
 38→
 39→    const [title, setTitle] = useState(journalData?.title);
 40→    const [showNotes, setShowNotes] = useState(true);
 41→    const [editorState , setEditorState] = useState(journalData?.content);
 42→    const [isUpdatingJournal, setIsUpdatingJournal] = useState(false);
 43→    const addUploadedImagePath = useCallback(() => {}, []);
 44→
 45→    const handlClickCloseEditor = (e) =>{
 46→        e.stopPropagation();
 47→        onClose();
 48→    }
 49→    const handleCloseNotes = (e) =>{
 50→        e.stopPropagation();
 51→        setShowNotes(false);
 52→    }
 53→
 54→    const saveEditJournal = async(e, journalId, journalContent, title) =>{
 55→        e.stopPropagation();
 56→        const formdata = new FormData();
 57→        if(journalId){
 58→            formdata.append('journalId', journalId)
 59→        }
 60→        if(journalContent){
 61→            formdata.append('content', journalContent)
 62→        }
 63→        if(title){
 64→            formdata.append('title', title);
 65→        }
 66→
 67→        try {
 68→            setIsUpdatingJournal(true)
 69→            const message = await updateJournal(session?.access_token, formdata);
 70→            if(message){
 71→                console.log(message)
 72→            }
 73→
 74→            queryClient.invalidateQueries(['userJournals', user?.userData?.[0].id])
 75→
 76→            setIsUpdatingJournal(false)
 77→            setTitle(null)
 78→            setEditorState(null)
 79→            onClose();
 80→        } catch (error) {
 81→            console.error("Error updating journal:", error);
 82→        } finally {
 83→            setTitle(null)
 84→            setEditorState(null)
 85→            setIsUpdatingJournal(false)
 86→            onClose()
 87→        }
 88→    }
 89→
 90→    const onChange = useCallback((state) => {
 91→        const jsonb = JSON.stringify(state.toJSON());
 92→        // console.log(jsonb)
 93→        setEditorState(jsonb);
 94→    }, [])
 95→
 96→    useEffect(() => {
 97→        console.log(journalData)
 98→    }, [journalData])
 99→
100→    return(
101→        <>
102→        <AnimatePresence>
103→        <motion.div 
104→        className='edit-journal-container'
105→        initial={{opacity:0, scale:0}}
106→        animate={{scale:1, opacity: 1, transition: {type: 'spring', stiffness: 200, damping: 25}}}
107→        exit={{opacity: 0, scale: 0}}
108→        >
109→            {showNotes && (
110→                <div className='important-notes-container'>
111→
112→                    <div className='notes-close-button-container'>
113→                        <div onClick={(e) => handleCloseNotes(e)} className='notes-close-button'>
114→                            <svg xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill="#d20000ff"><path d="m336-280-56-56 144-144-144-143 56-56 144 144 143-144 56 56-144 143 144 144-56 56-143-144-144 144Z"/></svg>
115→                        </div>
116→                    
117→                    </div>
118→
119→                    <p>Important Notes!</p>
120→                    <p>
121→                        You can only edit the <em>Title</em> and the <em>Text</em>.
122→                        <br />
123→                        You can remove and resize the <em>Images</em> but you can't add new <em>Images</em>.
124→                    </p>
125→
126→                </div>
127→            )}
128→            
129→            <div className='edit-journal-header-container'>
130→
131→                <div className='first-child-header-container'>
132→                     <div onClick={(e) => handlClickCloseEditor(e)} className='edit-journal-close-bttn'>
133→                        <svg xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill="currentcolor"><path d="m256-200-56-56 224-224-224-224 56-56 224 224 224-224 56 56-224 224 224 224-56 56-224-224-224 224Z"/></svg>
134→                    </div>
135→                    <div className='edit-journal-header'>
136→                        Edit Post
137→                    </div>
138→                </div>
139→
140→                <div className='second-child-header-container'>
141→                    <div onClick={(e) => saveEditJournal(e, journalData?.id, editorState, title)} className='save-edit-button'>
142→                        Save edit
143→                    </div>
144→                </div>
145→               
146→            </div>
147→
148→            <div className='title-container'>
149→                <input value={title} onChange={(e) => setTitle(e.target.value)} className='edit-joutnal-title-input' type="text"/>
150→            </div>
151→            
152→            <LexicalComposer initialConfig={{
153→                namespace: 'editContent',
154→                theme: theme,
155→                editable: true,
156→                editorState: typeof journalData?.content === 'string'
157→                ? journalData.content : JSON.stringify(journalData?.content),
158→                nodes: [HeadingNode, ImageNode, QuoteNode],
159→                onError(error){
160→                    throw error
161→                },
162→            }}>
163→                <div className="toolbar-wrapper">
164→                    <ToolBar addUploadedImagePath={addUploadedImagePath}/>
165→                </div>
166→
167→                <div className="editor-loader-wrapper">
168→                    {isUpdatingJournal && (
169→                        <BarLoader loading={isUpdatingJournal} width={'100%'} height={3} color="var(--accent-purple)" speedMultiplier={0.7}/>
170→                    )}
171→                </div>
172→
173→                <div className="editor-shell">
174→                    <RichTextPlugin
175→                        contentEditable={
176→                            <ContentEditable
177→                                className="editor-input"
178→                                aria-placeholder="Edit your post..."
179→                                placeholder={<div className="editor-placeholder">Edit your post...</div>}
180→                            />
181→                        }
182→                        ErrorBoundary={LexicalErrorBoundary}
183→                    />
184→
185→                    <ImagePlugin addUploadedImagePath={addUploadedImagePath}/>
186→                    <HistoryPlugin/>
187→                    <OnChangePlugin onChange={onChange}/>
188→                </div>
189→
190→            </LexicalComposer>
191→
192→        </motion.div>
193→        </AnimatePresence>
194→        </>
195→    )
196→}
197→
198→export default EditJournal;
